/*
 * NeuraSpend Custom Offline Dashboard Charting Library
 * Emulates standard Chart.js APIs to draw high-fidelity Canvas-based graphics.
 * Operates 100% offline without any network dependencies.
 */

class Chart {
    constructor(canvas, config) {
        this.canvas = typeof canvas === 'string' ? document.getElementById(canvas) : canvas;
        this.ctx = this.canvas.getContext('2d');
        this.config = config;
        
        // Ensure proper DPI scaling for razor-sharp visual text
        this.scaleDPR();

        // Bind resize updates
        window.addEventListener('resize', () => this.draw());
        
        // Initial paint
        this.draw();
    }

    scaleDPR() {
        const dpr = window.devicePixelRatio || 1;
        const rect = this.canvas.getBoundingClientRect();
        
        this.canvas.width = rect.width * dpr;
        this.canvas.height = rect.height * dpr;
        this.ctx.scale(dpr, dpr);
        
        this.width = rect.width;
        this.height = rect.height;
    }

    draw() {
        const dpr = window.devicePixelRatio || 1;
        const rect = this.canvas.getBoundingClientRect();
        if (rect.width === 0 || rect.height === 0) return;
        
        this.canvas.width = rect.width * dpr;
        this.canvas.height = rect.height * dpr;
        this.ctx.scale(dpr, dpr);
        
        this.width = rect.width;
        this.height = rect.height;

        this.ctx.clearRect(0, 0, this.width, this.height);

        const type = this.config.type;
        if (type === 'pie' || type === 'doughnut' || type === 'polarArea') {
            this.drawPieChart();
        } else if (type === 'bar') {
            this.drawVerticalBarChart();
        } else if (type === 'horizontalBar') {
            this.drawHorizontalBarChart();
        } else if (type === 'line') {
            this.drawLineChart();
        }
    }

    // Helper: Retrieve theme context details dynamically
    getThemeColors() {
        const theme = document.body.getAttribute('data-theme') || 'Dark';
        if (theme === 'Dark') {
            return {
                text: '#e5e5ea',
                grid: 'rgba(255, 255, 255, 0.08)',
                border: '#2c2c2c',
                card: '#1e1e1e'
            };
        } else {
            return {
                text: '#2c2c2e',
                grid: 'rgba(0, 0, 0, 0.05)',
                border: '#e5e5ea',
                card: '#ffffff'
            };
        }
    }

    drawPieChart() {
        const colors = this.getThemeColors();
        const data = this.config.data;
        const dataset = data.datasets[0];
        const values = dataset.data;
        const labels = data.labels || [];
        const bgColors = dataset.backgroundColor || ['#0a84ff', '#30d158', '#ffd60a', '#ff453a', '#8e8e93'];

        const total = values.reduce((sum, v) => sum + v, 0);
        const cx = this.width / 2;
        const cy = this.height / 2;
        const radius = Math.min(cx, cy) * 0.75;

        if (total === 0) {
            this.ctx.font = '13px Inter';
            this.ctx.fillStyle = colors.text;
            this.ctx.textAlign = 'center';
            this.ctx.fillText('No Data Available', cx, cy);
            return;
        }

        let startAngle = -Math.PI / 2;

        for (let i = 0; i < values.length; i++) {
            const val = values[i];
            const sliceAngle = (val / total) * Math.PI * 2;
            const endAngle = startAngle + sliceAngle;

            // Draw wedge
            this.ctx.beginPath();
            this.ctx.moveTo(cx, cy);
            this.ctx.arc(cx, cy, radius, startAngle, endAngle);
            this.ctx.closePath();
            
            this.ctx.fillStyle = bgColors[i % bgColors.length];
            this.ctx.fill();
            
            // Draw clean card gap boundaries
            this.ctx.strokeStyle = colors.card;
            this.ctx.lineWidth = 2;
            this.ctx.stroke();

            // Label percentage inside large slices
            const percent = (val / total) * 100;
            if (percent > 6) {
                const middleAngle = startAngle + sliceAngle / 2;
                const lx = cx + Math.cos(middleAngle) * (radius * 0.65);
                const ly = cy + Math.sin(middleAngle) * (radius * 0.65);
                
                this.ctx.font = 'bold 9px Inter';
                this.ctx.fillStyle = '#ffffff';
                this.ctx.textAlign = 'center';
                this.ctx.textBaseline = 'middle';
                this.ctx.fillText(`${percent.toFixed(0)}%`, lx, ly);
            }

            startAngle = endAngle;
        }

        // Draw center cutout for Doughnut aesthetics
        if (this.config.type === 'doughnut') {
            this.ctx.beginPath();
            this.ctx.arc(cx, cy, radius * 0.55, 0, Math.PI * 2);
            this.ctx.closePath();
            this.ctx.fillStyle = colors.card;
            this.ctx.fill();
        }

        // Draw small floating legends
        this.drawLegends(labels, bgColors);
    }

    drawLegends(labels, bgColors) {
        const colors = this.getThemeColors();
        this.ctx.font = '9px Inter';
        this.ctx.textAlign = 'left';
        this.ctx.textBaseline = 'middle';
        
        let lx = 10;
        let ly = this.height - 15;
        
        for (let i = 0; i < Math.min(labels.length, 5); i++) {
            const text = labels[i];
            
            // Draw indicator box
            this.ctx.fillStyle = bgColors[i % bgColors.length];
            this.ctx.fillRect(lx, ly - 4, 8, 8);
            
            this.ctx.fillStyle = colors.text;
            this.ctx.fillText(text, lx + 12, ly);
            
            lx += (this.ctx.measureText(text).width + 30);
            if (lx > this.width - 50) {
                lx = 10;
                ly -= 15;
            }
        }
    }

    drawVerticalBarChart() {
        const colors = this.getThemeColors();
        const data = this.config.data;
        const labels = data.labels || [];
        const dataset = data.datasets[0];
        const values = dataset.data || [];
        const barColor = dataset.backgroundColor || '#0a84ff';

        const padding = { left: 40, right: 15, top: 25, bottom: 30 };
        const chartWidth = this.width - padding.left - padding.right;
        const chartHeight = this.height - padding.top - padding.bottom;

        if (values.length === 0) {
            this.ctx.font = '13px Inter';
            this.ctx.fillStyle = colors.text;
            this.ctx.textAlign = 'center';
            this.ctx.fillText('No Data Available', this.width / 2, this.height / 2);
            return;
        }

        const maxVal = Math.max(...values, 100) * 1.15;
        const stepCount = 4;

        // Draw Y gridlines
        this.ctx.strokeStyle = colors.grid;
        this.ctx.lineWidth = 1;
        this.ctx.font = '8px Inter';
        this.ctx.fillStyle = colors.text;
        this.ctx.textAlign = 'right';
        this.ctx.textBaseline = 'middle';

        for (let i = 0; i <= stepCount; i++) {
            const val = (maxVal / stepCount) * i;
            const y = this.height - padding.bottom - (val / maxVal) * chartHeight;
            
            this.ctx.beginPath();
            this.ctx.moveTo(padding.left, y);
            this.ctx.lineTo(this.width - padding.right, y);
            this.ctx.stroke();

            this.ctx.fillText(Math.floor(val).toString(), padding.left - 8, y);
        }

        // Draw Bars
        const barSpacing = chartWidth / labels.length;
        const barWidth = barSpacing * 0.45;

        for (let i = 0; i < values.length; i++) {
            const val = values[i];
            const x = padding.left + (i * barSpacing) + (barSpacing - barWidth) / 2;
            const barH = (val / maxVal) * chartHeight;
            const y = this.height - padding.bottom - barH;

            // Draw Bar Rect
            this.ctx.fillStyle = barColor;
            this.ctx.fillRect(x, y, barWidth, barH);

            // Draw value on top of bar
            this.ctx.font = 'bold 8px Inter';
            this.ctx.fillStyle = colors.text;
            this.ctx.textAlign = 'center';
            this.ctx.fillText(Math.floor(val).toString(), x + barWidth / 2, y - 8);

            // Label X Axis
            this.ctx.font = '8px Inter';
            this.ctx.fillStyle = colors.text;
            this.ctx.textAlign = 'center';
            
            let labelText = labels[i];
            if (labelText.length > 8) {
                labelText = labelText.substring(0, 7) + '..';
            }
            this.ctx.fillText(labelText, x + barWidth / 2, this.height - padding.bottom + 12);
        }

        // Draw baseline axis
        this.ctx.strokeStyle = colors.border;
        this.ctx.lineWidth = 1.5;
        this.ctx.beginPath();
        this.ctx.moveTo(padding.left, this.height - padding.bottom);
        this.ctx.lineTo(this.width - padding.right, this.height - padding.bottom);
        this.ctx.stroke();
    }

    drawHorizontalBarChart() {
        const colors = this.getThemeColors();
        const data = this.config.data;
        const labels = data.labels || [];
        const dataset = data.datasets[0];
        const values = dataset.data || [];
        const barColor = dataset.backgroundColor || '#ffd60a';

        const padding = { left: 80, right: 30, top: 15, bottom: 15 };
        const chartWidth = this.width - padding.left - padding.right;
        const chartHeight = this.height - padding.top - padding.bottom;

        if (values.length === 0) {
            this.ctx.font = '13px Inter';
            this.ctx.fillStyle = colors.text;
            this.ctx.textAlign = 'center';
            this.ctx.fillText('No Data Available', this.width / 2, this.height / 2);
            return;
        }

        const maxVal = Math.max(...values, 100) * 1.15;
        
        // Draw bars
        const rowHeight = chartHeight / labels.length;
        const barH = rowHeight * 0.45;

        for (let i = 0; i < values.length; i++) {
            const val = values[i];
            const y = padding.top + (i * rowHeight) + (rowHeight - barH) / 2;
            const barW = (val / maxVal) * chartWidth;

            // Bar background Rect
            this.ctx.fillStyle = barColor;
            this.ctx.fillRect(padding.left, y, barW, barH);

            // Label category name
            this.ctx.font = '8px Inter';
            this.ctx.fillStyle = colors.text;
            this.ctx.textAlign = 'right';
            this.ctx.textBaseline = 'middle';
            
            let labelText = labels[i];
            if (labelText.length > 13) {
                labelText = labelText.substring(0, 11) + '..';
            }
            this.ctx.fillText(labelText, padding.left - 8, y + barH / 2);

            // Label value
            this.ctx.font = 'bold 8px Inter';
            this.ctx.fillStyle = colors.text;
            this.ctx.textAlign = 'left';
            this.ctx.textBaseline = 'middle';
            this.ctx.fillText(Math.floor(val).toString(), padding.left + barW + 8, y + barH / 2);
        }

        // Draw baseline axis
        this.ctx.strokeStyle = colors.border;
        this.ctx.lineWidth = 1.5;
        this.ctx.beginPath();
        this.ctx.moveTo(padding.left, padding.top);
        this.ctx.lineTo(padding.left, this.height - padding.bottom);
        this.ctx.stroke();
    }

    drawLineChart() {
        const colors = this.getThemeColors();
        const data = this.config.data;
        const labels = data.labels || [];
        const dataset = data.datasets[0];
        const values = dataset.data || [];
        const lineColor = dataset.borderColor || '#30d158';
        const fill = dataset.fill || false;

        const padding = { left: 45, right: 20, top: 25, bottom: 30 };
        const chartWidth = this.width - padding.left - padding.right;
        const chartHeight = this.height - padding.top - padding.bottom;

        if (values.length === 0) {
            this.ctx.font = '13px Inter';
            this.ctx.fillStyle = colors.text;
            this.ctx.textAlign = 'center';
            this.ctx.fillText('No Data Available', this.width / 2, this.height / 2);
            return;
        }

        const maxVal = Math.max(...values, 100) * 1.15;
        const stepCount = 4;

        // Draw Y lines
        this.ctx.strokeStyle = colors.grid;
        this.ctx.lineWidth = 1;
        this.ctx.font = '8px Inter';
        this.ctx.fillStyle = colors.text;
        this.ctx.textAlign = 'right';
        this.ctx.textBaseline = 'middle';

        for (let i = 0; i <= stepCount; i++) {
            const val = (maxVal / stepCount) * i;
            const y = this.height - padding.bottom - (val / maxVal) * chartHeight;
            
            this.ctx.beginPath();
            this.ctx.moveTo(padding.left, y);
            this.ctx.lineTo(this.width - padding.right, y);
            this.ctx.stroke();

            this.ctx.fillText(Math.floor(val).toString(), padding.left - 8, y);
        }

        // Compute points coordinates
        const spacing = chartWidth / (labels.length - 1 || 1);
        const points = [];

        for (let i = 0; i < values.length; i++) {
            const val = values[i];
            const x = padding.left + (i * spacing);
            const y = this.height - padding.bottom - (val / maxVal) * chartHeight;
            points.push({ x, y });
        }

        // Fill area beneath curve
        if (fill && points.length > 0) {
            this.ctx.beginPath();
            this.ctx.moveTo(points[0].x, this.height - padding.bottom);
            for (const pt of points) {
                this.ctx.lineTo(pt.x, pt.y);
            }
            this.ctx.lineTo(points[points.length - 1].x, this.height - padding.bottom);
            this.ctx.closePath();

            // Create beautiful glowing linear gradient fill
            const grad = this.ctx.createLinearGradient(0, padding.top, 0, this.height - padding.bottom);
            grad.addColorStop(0, 'rgba(10, 132, 255, 0.25)');
            grad.addColorStop(1, 'rgba(10, 132, 255, 0.0)');
            
            this.ctx.fillStyle = grad;
            this.ctx.fill();
        }

        // Draw main line path
        if (points.length > 0) {
            this.ctx.beginPath();
            this.ctx.moveTo(points[0].x, points[0].y);
            for (let i = 1; i < points.length; i++) {
                this.ctx.lineTo(points[i].x, points[i].y);
            }
            this.ctx.strokeStyle = lineColor;
            this.ctx.lineWidth = 2.5;
            this.ctx.stroke();
        }

        // Draw markers and labels
        for (let i = 0; i < points.length; i++) {
            const pt = points[i];

            // Draw small circular node
            this.ctx.beginPath();
            this.ctx.arc(pt.x, pt.y, 4, 0, Math.PI * 2);
            this.ctx.fillStyle = '#0a84ff';
            this.ctx.strokeStyle = '#ffffff';
            this.ctx.lineWidth = 1;
            this.ctx.fill();
            this.ctx.stroke();

            // Draw x axis date
            if (i % Math.ceil(labels.length / 5) === 0 || i === labels.length - 1) {
                this.ctx.font = '8px Inter';
                this.ctx.fillStyle = colors.text;
                this.ctx.textAlign = 'center';
                
                let labelText = labels[i];
                if (labelText.length > 8) {
                    labelText = labelText.substring(5); // Show e.g. 05-23
                }
                this.ctx.fillText(labelText, pt.x, this.height - padding.bottom + 12);
            }
        }
    }
}
